#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(int n, vector<vector<int>>& flights, int src, int dst, int K) {
        const long long INF = 1e15;
        vector<long long> dist(n, INF);
        dist[src] = 0;
        for (int i = 0; i <= K; ++i) {
            vector<long long> tmp = dist;
            for (auto &f : flights) {
                int u = f[0], v = f[1];
                int w = f[2];
                if (dist[u] == INF) continue;
                if (dist[u] + w < tmp[v]) {
                    tmp[v] = dist[u] + w;
                }
            }
            dist.swap(tmp);
        }
        return dist[dst] == INF ? -1 : (int)dist[dst];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, m;
    if (!(cin >> n >> m)) return 0;
    int m_check;
    cin >> m_check; // as per input format
    vector<vector<int>> flights;
    flights.reserve(m_check);
    for (int i = 0; i < m_check; ++i) {
        int u, v, w;
        cin >> u >> v >> w;
        flights.push_back({u, v, w});
    }
    int src, dst, K;
    cin >> src >> dst >> K;
    Solution sol;
    int ans = sol.solve(n, flights, src, dst, K);
    cout << ans << "\n";
    return 0;
}
